import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"24. Casual Conversion","description":"","frontmatter":{"title":"24. Casual Conversion","eba":"Health Allied & Managers Admin 2021-2025","topics":["employment","casual-conversion"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/employment-types/24-casual-conversion.md","filePath":"ebas/has-managers-admin/common-terms/employment-types/24-casual-conversion.md"}'),n={name:"ebas/has-managers-admin/common-terms/employment-types/24-casual-conversion.md"};function s(i,e,l,m,p,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_24-casual-conversion" tabindex="-1">24. Casual Conversion <a class="header-anchor" href="#_24-casual-conversion" aria-label="Permalink to &quot;24. Casual Conversion&quot;">​</a></h1><p><strong>24.1</strong> Where a casual Employee has worked a regular pattern of hours on an ongoing basis over a period of 26 weeks or more, which without significant adjustment they could continue to perform as a part-time or full-time Employee, the Employer must offer to convert the Employee to part-time or full-time employment (reflecting the pattern of hours worked).</p><p><strong>24.2</strong> Despite subclause 24.1, an Employer is not required to make an offer to an Employee under that subclause if there are reasonable grounds not to make the offer and the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of deciding not to make the offer. Reasonable grounds include:</p><p><strong>(a)</strong> the Employee’s position will cease to exist in the period of 12 months after the time of deciding not to make the offer;</p><p><strong>(b)</strong> the hours of work which the Employee is required to perform will be significantly reduced in that period;</p><p><strong>(c)</strong> there will be a significant change in either or both of the following in that period:</p><p><strong>(i)</strong> the days on which the Employee’s hours of work are required to be performed;</p><p><strong>(ii)</strong> the times at which the Employee’s hours of work are required to be performed; which cannot be accommodated within the days or times the Employee is available to work during that period;</p><p>PART C – TYPES OF EMPLOYMENT AND TERMINATION OF EMPLOYMENT</p><p><strong>(d)</strong> making the offer would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory.</p><p><strong>24.3</strong> Where an Employer does not make an offer of conversion in reliance on clause 24.2, the Employer must give written notice to the Employee advising them that an offer will not be made and including details of the reasons for not making the offer (including the grounds relied upon).</p><p><strong>24.4</strong> An Employee must give a written response no later than 21 days from the date of the offer (by either an Employee or Employer). If the Employee fails to give a written response within 21 days, they are taken to have refused the offer.</p><p><strong>24.5</strong> Where an Employee converts from casual to full or part-time employment, the Employee’s minimum weekly hours will be those worked on a regular and systematic basis as described in subclauses 24.1 and 24.2 above, and the provisions of <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/20-full-time-employment.html">clause 20</a> (Full-time Employment) or 21 (Regular Part-Time Employment) (whichever is relevant) will apply.</p><p><strong>24.6</strong> Where such a conversion occurs, the Employee will be provided with a Letter of Appointment within 21 days of the acceptance, setting out the revised employment arrangements (including hours of work), acknowledging any period/s of casual employment with the Employer.</p><p>Plain language terms: casual to permanent, conversion to permanent.</p>',15)])])}const u=o(n,[["render",s]]);export{d as __pageData,u as default};
